\begin{aligned}
\frac{\partial \theta}{\partial x}
&= \frac{\partial \arctan(u)}{\partial u} \cdot \frac{\partial u}{\partial x}\\
&= \frac{1}{1 + u^2} \cdot \frac{1}{z} \frac{1}{2} (x^2+y^2)^{-1/2} 2x\\
