&= \frac{1}{\frac{x^2+y^2 + z^2}{z^2}} \cdot \frac{x}{z \sqrt{x^2+y^2}}\\
&= \frac{z^2}{r^2} \cdot \frac{x}{z \sqrt{x^2+y^2}}\\
&= \frac{zx}{r^2 \sqrt{x^2+y^2}}\\
\end{aligned}

